var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"총사대장님! 서쪽에서 더 몰려옵니다!","JPN":"銃士隊長！　西からもっと来ます！","ENG":"Sir! More incoming from the west!","TWN":"隊長！有一群從西邊衝過來！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"사수들은 탄환을 장전하도록! 내가 시간을 벌겠다!","JPN":"撃ち手は弾丸を装填しろ！　私が時間を稼ぐ！","ENG":"Reload your weapons! I'll buy you some time!","TWN":"狙擊手補充子彈！我來爭取時間！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"대단해……. 산탄총도 통하지 않던 괴물들을 창 하나로 해치우다니…….","JPN":"すごい……散弾銃も通じなかった化け物を槍一本でやっつけるなんて……","ENG":"Astounding... Even a shotgun couldn't hurt that monster, but he killed it with just a spear...","TWN":"好厲害……連散彈槍都無法對付的怪物，竟然只用一搶就解決掉……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"저희 총사대장님은 노르드나빅을 대표하는 성자들 중에서도 가장 강한 분이시니까요.","JPN":"我々の銃士隊長はノルドナビックを代表する聖者の中でも一番強い方ですから。","ENG":"Our General Musketeer is the strongest of all Helgons in Nordnavik.","TWN":"因爲我們隊長是代表諾爾德萊比的聖者中最強的一個。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"성자……? 실제로 본 건 처음이네요. 어떤 괴물도 맨손으로 때려눕힐 정도로 힘이 장사라고 들었는데.","JPN":"聖者……？　実際に見るのは初めてです。どんな化け物でも素手で倒せるほど力が強いと聞きましたけど。","ENG":"Helgon...? I've never seen one before. I only heard stories about them being strong enough to take down any monster with nothing but their bare hands...","TWN":"聖人……？這還是我第一次親眼看到，聽說聖者是可以赤手空拳打倒任何怪物的大力士呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"하하, 맨손이라니. 그런 얘기는 저도 처음 듣는군요.","JPN":"はは、素手だなんて。そんな話は私も初めて聞きますね。","ENG":"Haha! Bare hands? That's the first time I'm hearing that!","TWN":"哈哈，赤手空拳嗎？這我還是第一次聽說呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"총사대의 성자들은 다들 비밀리에 활동한다고 들었는데, 혹시 저도 보안법으로 끌려가게 되는 걸까요?","JPN":"銃士隊の聖者は秘密裡に活動するものと聞いていますが、私も保安法の違反で引っ張られるのでしょうか？","ENG":"But I thought Helgons in the Musketeer Division were supposed to keep their identities hidden. Will I face legal consequences for knowing this?","TWN":"我聽說射擊隊的聖人都是暗中行動的，難道我有觸犯保安法嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"그런 건 낭설이니 걱정하지 않으셔도 됩니다. 그보다 다친 곳은 없으십니까?","JPN":"それは根も葉もない噂ですので気にしなくて結構です。それより、お怪我はありませんか？","ENG":"You won't have to worry about that. But more importantly, are you hurt?","TWN":"那些都只是不實的謠言，你不用擔心。倒是你有沒有受傷？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"전 괜찮아요! 그보다 헛간 지하에 마을 아이들이 숨어 있어요!","JPN":"私は大丈夫です！　それより小屋の地下に村の子供たちが隠れているんです！","ENG":"I'm good! Oh, the children are hiding in the barn basement!","TWN":"不用管我！村裡的孩子都在躲在穀倉的地下室！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"걱정 마십시오. 마을은 이미 다른 병사들이 가서 구조를 마친 상황입니다.","JPN":"ご心配なく。村に向かった他の兵士によりすでに救助を終えています。","ENG":"Rest assured. The other soldiers have already finished rescuing the villagers.","TWN":"請放心，其他的士兵已經前往救援。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"아아……. 정말 감사합니다. 이대로 어떻게 되나 무서웠어요.","JPN":"ああ……本当にありがとうございます。このまま死ぬかと思って怖かったんです。","ENG":"Oh... Thank you so much. I was so scared something might've happened to them...","TWN":"嗚……非常感謝，我剛真的很害怕，不知道這樣下去會發生什麼事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"아닙니다. 아이들을 지키려고 침식체를 유인하시다니, 만삭의 몸인데도 대단하시군요.","JPN":"いいえ。子供たちを守るために侵食体を誘き出すなんて、身重の体でなかなかできることではありません。","ENG":"No need. But you were brave to try to and save those children from the C.O.s while you were pregnant.","TWN":"沒事的。你都快要臨盆了，竟然為了保護孩子們，而將自己當作侵蝕體的誘餌，真的是好偉大。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"저 괴물들을 침식체라고 부르는군요…….","JPN":"あの化け物は侵食体というのですね……","ENG":"Those monsters... So \\"C.O.s.” is what you call them...","TWN":"那些怪物叫侵蝕體嗎……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"그런데 저기……. 수도에 계셔야 할 왕립군 분들이 왜 이런 데 오신 거죠?","JPN":"ところで、あの……首都にいるはずの王立軍がどうしてこんなところに？","ENG":"Oh, and if you don't mind me asking... What is the Royal Army doing out here instead of being in the capital?","TWN":"不過……皇家軍隊不是應該在首都嗎？你們怎麼會來這種地方呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"죄송합니다, 부인. 중요한 임무를 수행 중이라는 것 말고는 자세히 말씀드릴 수 없습니다.","JPN":"申し訳ございませんが、奥さん。重要な任務を遂行中であるということ以外には詳しくお話しすることができません。","ENG":"I'm sorry, ma'am. I can't tell you anything more than that we are on a crucial mission.","TWN":"太太，很抱歉，我只能告訴你，我們正在執行重要任務，其餘的無可奉告。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VILLAGER_BORDER_NULL_WOMAN","text":{"KOREA":"방금 그건 뭐죠? 나무들이 흔들렸는데…?","JPN":"今のは何でしょうか？　木々が揺れましたけど……？","ENG":"What was that? I saw the trees shake...!","TWN":"剛剛是怎麼回事？樹都搖搖晃晃的…？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"좋은 징조가 아니라는 건 확실하군요.","JPN":"いい兆しではないのは確かなようですね。","ENG":"That’s definitely not a good omen.","TWN":"確實不是好預兆。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};